package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.PersoonsFiscaliteit;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Janeen;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import com.google.common.collect.Sets;
import lombok.extern.slf4j.Slf4j;

import java.util.Collection;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SCHOOLVERLATER_KEY;

@Slf4j
public class CheckSchoolVerlater extends AbstractBerekenBv {

    public CheckSchoolVerlater(ConstantManager constantManager, NlpGlobalService service) {
        super(constantManager, service);
    }

    private static final Set<Hoedanigheid> HOEDANIGHEDEN_SCHOOLVERLATER =
            Sets.immutableEnumSet(Hoedanigheid.VASTBENOEMDEN, Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN, Hoedanigheid.GESUBSIDIEERDE_CONTRACTUELEN,
                    Hoedanigheid.TOEZICHT_BEGELEIDING_BIJLES);

    private static final Set<LnedefRegBv> GEEN_REGIMES_SCHOOLVERLATER =
            Sets.immutableEnumSet(LnedefRegBv.VD_BV_10_KWG__NBB, LnedefRegBv.NBB_NFF, LnedefRegBv.VD_BV_10_FTSW_NBB, LnedefRegBv.VD_BV_50_VAC_TOE_NBB,
                    LnedefRegBv.VD_BV_50_KOSTEN_NBB, LnedefRegBv.VD_BV_10_MOB_VERG_NBB);

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        RegulManager regulManager = mainContext.getUnchecked(REGUL_MANAGER_KEY);
        initFiscaleConstanten(rekenTijd);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        PersoonsFiscaliteit persoonsFiscaliteit = RekenTools.getPersoonsFiscaliteitLaatsteGegevens(persoon);
        boolean isSchoolVerlater = persoonsFiscaliteit.getSchoolVerlater().equals(Janeen.JA.getCode());
        log.debug("isSchoolVerlater: {}", isSchoolVerlater);
        if (isSchoolVerlater) {
            checkSchoolVerlaterInLaatsteKwartaal(regulManager, rekenTijd);
            LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
            Money totaalBbSchoolverlater = Money.ZERO;
            for (Opdracht opdracht : persoon.getOpdrachten()) {
                if (HOEDANIGHEDEN_SCHOOLVERLATER.contains(opdracht.getHoedanigheid())) {
                    Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
                    for (LoonElement element : loonElementen) {
                        log.trace("element: {}", element);
                        LnedefRegBv regime = element.getRegimeBv();
                        log.trace("regime: {}, element: {}", regime, element);
                        if (!GEEN_REGIMES_SCHOOLVERLATER.contains(regime)) {
                            log.trace("tussenstand totaalBbSchoolverlater= {}+{}", totaalBbSchoolverlater, element.getPropertyMoney(BELASTBAAR_KEY));
                            totaalBbSchoolverlater = totaalBbSchoolverlater.add(element.getPropertyMoney(BELASTBAAR_KEY));
                            log.trace("tussenstand totaalBbSchoolverlater: {}", totaalBbSchoolverlater);
                        }
                    }
                }
            }
            log.debug("totaalBbSchoolverlater: {}", totaalBbSchoolverlater);
            Money schoolverlaterGrens = fiscaleConstanten.getSchoolverlaterGrens();
            log.debug("schoolverlaterGrens: {}", schoolverlaterGrens);
            if (totaalBbSchoolverlater.compareTo(schoolverlaterGrens) <= 0) {
                for (Opdracht opdracht : persoon.getOpdrachten()) {
                    if (HOEDANIGHEDEN_SCHOOLVERLATER.contains(opdracht.getHoedanigheid())) {
                        RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
                        opdrachtContext.put(SCHOOLVERLATER_KEY, true);
                    }
                }
            }
        }
        return CONTINUE_PROCESSING;
    }

    private void checkSchoolVerlaterInLaatsteKwartaal(RegulManager regulManager, RekenTijd rekenTijd) {
        if (rekenTijd.beginDatum.getMonthOfYear() < 10) {
            regulManager.doRegulException(null, Regulkode.SCHOOLVERLATER_ONGELDIG);
        }
    }
}
